export type MissionPreferences = {
  primaryMode?: MissionMode;
  secondaryMode?: MissionMode;
  preferredIntensity?: MissionIntensity;
  preferredCostTier?: CostTier;
  privateFirst?: boolean;
  hasChildren?: boolean;
  maxMinutes?: number;
};

export function selectMissionOfTheDay(preferences: MissionPreferences = {}, date = new Date()): Mission {
  const daySeed = Number(`${date.getFullYear()}${date.getMonth() + 1}${date.getDate()}`);
  const candidates = missions
    .filter((mission) => !preferences.primaryMode || mission.mode === preferences.primaryMode || mission.mode === preferences.secondaryMode)
    .filter((mission) => !preferences.privateFirst || mission.soloEnabled)
    .filter((mission) => !preferences.maxMinutes || mission.estimatedMinutes <= preferences.maxMinutes);

  const pool = candidates.length > 0 ? candidates : missions;
  const scored = pool.map((mission, index) => {
    let score = 0;
    if (mission.mode === preferences.primaryMode) score += 60;
    if (mission.mode === preferences.secondaryMode) score += 30;
    if (mission.intensity === preferences.preferredIntensity) score += 20;
    if (mission.costTier === preferences.preferredCostTier) score += 20;
    if (mission.costTier === "gratis") score += 8;
    if (preferences.hasChildren && mission.familyEnabled) score += 20;
    if (preferences.privateFirst && mission.soloEnabled) score += 12;
    score += ((daySeed + index * 17) % 29);
    return { mission, score };
  });

  scored.sort((a, b) => b.score - a.score);
  return scored[0].mission;
}
